package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.TupleQueryResult;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/** Native row projection must keep primitive ids until callers actually inspect a value. */
public class LmdbNativeLazyProjectedResultTest {

	private static final String EX = "http://example.com/";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection connection = repository.getConnection()) {
			ValueFactory vf = connection.getValueFactory();
			IRI predicate = vf.createIRI(EX, "value");
			for (int i = 0; i < 64; i++) {
				connection.add(vf.createIRI(EX, "s" + i), predicate,
						vf.createLiteral("stored literal payload " + i));
			}
		}
		NativeProjectedBindingSet.CREATED.set(0);
		NativeProjectedBindingSet.MATERIALIZED_VALUES.set(0);
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	@Test
	public void projectionRetainsPrimitiveIdsUntilBindingAccess() {
		BindingSet first;
		try (SailRepositoryConnection connection = repository.getConnection();
				TupleQueryResult rows = connection.prepareTupleQuery(
						"SELECT ?s ?value WHERE { ?s <" + EX + "value> ?value }").evaluate()) {
			int count = 0;
			first = null;
			while (rows.hasNext()) {
				BindingSet row = rows.next();
				if (first == null) {
					first = row;
				}
				count++;
			}
			assertThat(count).isEqualTo(64);
		}

		assertThat(NativeProjectedBindingSet.CREATED.get()).isEqualTo(64);
		assertThat(NativeProjectedBindingSet.MATERIALIZED_VALUES.get()).isZero();
		assert first instanceof NativeProjectedBindingSet;

		assertThat(first.getValue("value").stringValue()).startsWith("stored literal payload ");
		assertThat(NativeProjectedBindingSet.MATERIALIZED_VALUES.get()).isEqualTo(1);
		assertThat(first.getValue("value")).isSameAs(first.getValue("value"));
		assertThat(NativeProjectedBindingSet.MATERIALIZED_VALUES.get()).isEqualTo(1);
	}
}
